#include <stdio.h>
#include <stdlib.h>
#include <algorithm>

long long gcd_ll(long long a, long long b) {
    while (b) {
        long long t = a % b;
        a = b;
        b = t;
    }
    return a;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long A, B;
        scanf("%lld %lld", &A, &B);
        long long g = gcd_ll(A, B);
        printf("%lld\n", A - g);
    }
    return 0;
}

